def merge(lists):
    first_elements = []
    last_elements = []
    middle_elements = []
    for sublist in lists:
        if sublist:  # Ensure sublist is not empty
            first_elements.append(sublist[0])
            last_elements.append(sublist[-1])
            if len(sublist) > 2:
                middle_elements.extend(sublist[1:-1])
    if middle_elements:
        return [first_elements, middle_elements, last_elements]
    else:
        return [first_elements, last_elements]

def average_tuple(data):
    total_sum = 0
    count = 0
    averages = []
    for subtuple in data:
        total_sum = 0
        count = 0
        for element in subtuple:
            total_sum += element
            count += 1
        if count > 0:
            averages.append(round(total_sum / count, 2))
    return averages
